var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐야, 저 사람이 누구길래 아저씨들이 죄다 조용해?","JPN":"なに？　あの人が喋り始めたら、おじさんたちみんな黙り込んだよ？","ENG":"Who is she? Why did all the old guys go quiet?","TWN":"什麼啊，那個人是誰，叔叔們怎麼都安靜了？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>전 세대</color> 백양궁의 기사. 메데이아 데이비스.","JPN":"<color=#ffd34c>先代</color>の白羊宮の騎士、メデイア・デイヴィス。","ENG":"The Knight of Aries from the <color=#ffd34c>previous generation</color>. Medea Davis.","TWN":"<color=#ffd34c>前世代</color>白羊宮的騎士。美狄亞·戴維斯。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"전임 기사단장과 함께 조디악 나이츠의 황금세대를 이끈 기사들 중 한 명입니다.","JPN":"前騎士団長と共にゾディアックナイツの黄金世代を率いた騎士の一人です。","ENG":"One of the knights who led the golden generation of the Zodiac Knights alongside the former captain.","TWN":"他是與前任騎士團長一起引領十二宮騎士黃金時代的騎士之一。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"비록 영광이 퇴색되고 그녀 역시 전선에서 물러났다고는 하나, 과거를 아는 이들에겐 여전히 선망의 대상이죠.","JPN":"たとえ栄光が色褪せ、彼女も戦線から身を引いているとはいえ、過去を知る者たちにとっては依然として憧れの人です。","ENG":"Though the luster of her glory has dimmed and she has retired from the front lines, she remains revered by those who remember her past.","TWN":"雖然榮耀已褪色，她也從前線退下，但對那些了解過去的人來說，她仍然是令人景仰的對象。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어… 유명한 사람인 것 같은데 난 왜 들은 기억이 없지?","JPN":"え……すごく有名な人みたいだけど、なんで名前を聞いたことないんだろう？","ENG":"Huh... sounds like she's famous, so why don't I remember hearing about her?","TWN":"呃……她好像很有名，但我怎麼沒聽說過呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그건 리브 경이 듣고 싶은 것만 듣고 살아서 그래요.","JPN":"それはリブ卿が聞きたいことしか聞いてないからです。","ENG":"Because you only pay attention to what you want, Dame Liv.","TWN":"那是因為莉芙只聽自己想聽的東西。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"품성은 몰라도 역대 기사단장직에 버금가는 실력을 지닌 줄리아 레온하르트.","JPN":"品性はともかく、歴代の騎士団長に匹敵する実力を持つジュリア・レオンハルト。","ENG":"Julia Leonhardt. Her character is debatable, but her skills were on par with any past Knight Captain.","TWN":"雖然品性不明，但茱莉亞·里恩哈特擁有接近歷代騎士團長的實力。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그녀가 어느 파벌에서도 단장직에 오르지 못했다는 점이 전 세대의 실력을 뒷받침하죠.","JPN":"彼女がどの派閥でも団長職に就けなかったことが、前の世代のすごさを証明しています。","ENG":"The fact that she never made captain despite that just shows how strong that generation was.","TWN":"她未能在任何派系中擔任團長職務，這證明了上一代的實力。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"다른 단원들의 실력 또한 명성이 자자했던 만큼, 기사단에서 그들의 입지는 상당합니다.","JPN":"他の団員たちの実力もまた評判に違わぬものであり、騎士団内での彼らの立場は相当なものです。","ENG":"Given the renown of their past prowess, the other members, too, hold considerable standing within the Order.","TWN":"其他成員的實力也同樣名聲顯赫，因此他們在騎士團中的地位相當高。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"하지만… 저분이 들고 있는 건 별의 무구 아닌가요?","JPN":"でも……あの方が持っているのは星の武具じゃないですか？","ENG":"But... isn't that a Star Armament she's carrying?","TWN":"但是… 那位拿著的不是星之武具嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"전선에서 물러나셨다면, 어째서 무구를?","JPN":"戦線から身を引いているなら、どうしてまだ武具を？","ENG":"If she's retired, why would she still have it?","TWN":"既然已經退出前線，為什麼還要武裝自己？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"분파 소속이었던 저를 기사단에 들이고 양자리 기사직을 물려주신 게 누님이에요.","JPN":"分派所属だった私を騎士団に迎え入れ、牡羊座の騎士を譲ってくださったのがメデイアさんです。","ENG":"She was the one who brought me into the Order and passed down the Aries seat to me.","TWN":"是姊姊讓我這個曾經屬於分派的人加入了騎士團，並繼承了白羊座騎士的職位。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"다만, 제가 견습기사 신분이라 아직 무구는 누님에게 있죠.","JPN":"ただ、私はまだ見習い騎士なので、武具はメデイアさんが持っています。","ENG":"But since I'm still a trainee, the Armament is still in her possession.","TWN":"不過，我還是見習騎士，所以武器還在姊姊那裡。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어라. 한솔이 무구는 죽도가 아니었어?","JPN":"え？　イチロウの武具は竹刀じゃなかったの？","ENG":"Wait. I thought your Armament was just a bamboo sword?","TWN":"咦，楊瀚的武器不是竹刀嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그럴 리가 없잖아요! 애초에 평범한 죽도라고 몇 번이나 말했다고요!","JPN":"そんなわけないでしょう！　そもそも、普通の竹刀だって何度も言ったじゃないですか！","ENG":"Of course not! I've told you a dozen times it's just a regular training sword!","TWN":"怎麼可能！我已經說過好幾次這只是普通的竹刀了！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"미안. 그런 컨셉인 줄.","JPN":"ごめん。そういう設定だと思ってた。","ENG":"Oops. Thought it was your thing.","TWN":"抱歉，我還以為是偽裝。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"오랜만이에요, 에스테로사 경. 이런 식의 재회라 아쉬울 따름이네요.","JPN":"お久しぶりです、エステロサ卿。再会がこのような形となってしまい、残念でなりません。","ENG":"It's been a while, Dame Esterosa. A shame we meet like this again.","TWN":"好久不見了，艾斯特洛索。以這樣的方式重逢，真是遺憾啊。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"예. 오랜만입니다, 메데이아 경.","JPN":"お久しぶりです。メデイア卿。","ENG":"Yes, it has. Dame Medea.","TWN":"是的。好久不見，美狄亞。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그런데… 가문의 목소리를 전하러 왔다는 것은?","JPN":"ところで……デイヴィス家の声を届けに来たというのは？","ENG":"But... when you say you're here to speak for your house?","TWN":"但是……你是來傳達家族的聲音的嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"문자 그대로의 의미예요.","JPN":"文字通りの意味ですわ。","ENG":"I mean exactly that.","TWN":"就是字面上的意思。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"데이비스 가문은, 현 단장인 에스테로사 경을 두둔합니다.","JPN":"デイヴィス家は、現団長であるエステロサ卿を支持します。","ENG":"House Davis supports the current captain, Dame Esterosa.","TWN":"戴維斯家族支持現任團長艾斯特洛索。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"안타깝지만 메데이아 경. 귀 가문에 관계없이 해당 안건은 가결된 것이나 다름없네.","JPN":"残念だがメデイア卿、デイヴィス家の意見は関係なく、この件は可決したも同然だ。","ENG":"Regrettably, Dame Medea. That matter has essentially already been decided, regardless of your house.","TWN":"很遺憾，美狄亞。無論你的家族如何，這項議案都已通過。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"이미 원로들의 뜻 또한 만장일치로…….","JPN":"すでに元老たちの意見も全員一致して……","ENG":"The Elder Council was unanimous...","TWN":"已經達成了元老們的一致意見……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"레드시프트의 잠적 이후 원로원은 공석을 메우기 위한 인원을 급히 선별했죠.","JPN":"レッドシフトの失踪以来、元老院は空席を埋めるための人員を急いで選別しました。","ENG":"After the Red Shift vanished, the Elder Council rushed to fill the vacant seats.","TWN":"紅移失蹤後，元老院急忙挑選人員填補空缺。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"때문에 무구의 선택을 받았던 자만이 입회할 수 있었던 이전과 달리 현 원로원은 임시체제에 불과합니다.","JPN":"よって、武具に選ばれた者だけが入会できた昔とは違い、現在の元老院は臨時体制にすぎません。","ENG":"Unlike before, when only those chosen by a Star Armament could join, the current Council is merely provisional.","TWN":"因此，現任元老院只是一個臨時體制，不像以前只有被選中的人才能加入。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"만약 자격을 갖춘 이가 나타난다면, 당연히 그 자리를 승계해야겠지요.","JPN":"もし資格を持つ者が現れれば、当然その座を引き渡すべきでしょう。","ENG":"So if someone qualified appears, they should naturally take the seat.","TWN":"如果有合適的人出現，當然應該繼承那個位置。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"메, 메데이아 경? 자네 설마……!!","JPN":"メ、メデイア卿？　そなたはまさか……！！","ENG":"D-Dame Medea? You're not saying...!","TWN":"美、美狄亞？你該不會是……！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"예. 별의 무구의 선택을 받은 자로서, 저 메데이아가 원로원의 권한을 요청합니다.","JPN":"ええ、星の武具に選ばれた者として、私メデイアは元老院の資格を要請します。","ENG":"Correct. As someone chosen by a Star Armament, I, Medea, hereby request Elder authority.","TWN":"是的。作為被星之武具選中的人，我美狄亞請求使用元老院的權力。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그, 그것은 받아들일 수 없다! 본디 원로 자리의 승계는 절차를 따라 진행돼야 할 터!","JPN":"そ、それは受け入れられない！　本来元老の座の承継は、手続きを踏んで行われるべきだ！","ENG":"Unacceptable! The succession of Elder seats must follow proper procedure!","TWN":"那，那是無法接受的！原本元老之位元的繼承應該按照程式進行才對！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"사안을 그때까지 미룰 수는 없지 않은가!!","JPN":"その時までこの件の決定を先延ばしにするわけにはいかんだろう！！","ENG":"We can't delay such an urgent matter until then!","TWN":"難道能把事情拖到那個時候嗎！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"절차라니. 모순된 말씀을 하시네요.","JPN":"手続きだなんて。矛盾していますわね。","ENG":"Procedure? How contradictory.","TWN":"程式？你這話可真矛盾啊。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"프레이더 경의 말씀대로라면, 본 사안도 양대 파벌을 대표하는 기사의 입석 하에 이루어져야 하잖아요?","JPN":"フレイダー卿のおっしゃる通りだとすれば、今回の案件も両大派閥を代表する騎士の立ち合いの下、決定を下すべきでしょう？","ENG":"By Sir Frayder's own logic, this matter should be overseen by representatives of both factions, yes?","TWN":"按照弗雷德的說法，這件事也應該在代表兩大派系的騎士的見證下進行吧？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"허나 레드시프트의 단원들은 잠적한지 오래일세.","JPN":"しかし、レッドシフトの団員は随分前から行方不明になっている。","ENG":"But the Red Shift members have long since disappeared.","TWN":"然而紅移小組的成員們已經失蹤很久了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"불가피한 상황이 발생하였을 때, 원로원이 그 뜻을 대신할 수 있다는 것을 알고 있지 않나!","JPN":"やむを得ぬ事態が生じたときは、元老院がその意志を代行できることぐらい、そなたも知っているだろう！","ENG":"And in unavoidable situations, the Council can act on their behalf. You know that.","TWN":"難道你不知道在不可抗力的情況下，元老院可以代替其意志嗎！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아뇨. 기사단이 행방을 알고 있는 레드시프트 단원이 한 명 존재합니다.","JPN":"いいえ、騎士団が行方を把握しているレッドシフトの団員が1人、存在します。","ENG":"No. There is one Red Shift member whose whereabouts are known.","TWN":"不。騎士團中有一名成員知道紅移的下落。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그도 그럴게. 관리국이 공인한 S급 카운터니까요.","JPN":"それはそうですわよね、管理局公認のS級カウンターですもの。","ENG":"Plus, she's an Administration confirmed Grade S Counter.","TWN":"知道也是理所當然的，因為他是管理局公認的S級制裁者。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"줄리아 레온하르트. 기사의 명예를 더럽힌 그 여자를 말하는 건가?","JPN":"ジュリア・レオンハルト。騎士の名誉を汚したあの女のことか？","ENG":"Julia Leonhardt. You mean that woman who disgraced the honor of the Order?","TWN":"茱莉亞·里恩哈特。你是在說那個玷污騎士榮譽的女人嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"말도 안 돼. 이런 중요한 안건을 어찌 그자에게 맡길 수 있단 말인가!","JPN":"バカなことを。このような重要案件を彼女に任せるなど言語道断だ！","ENG":"Ridiculous! We can't entrust something this important to her!","TWN":"這不可能。怎麼能把這麼重要的議題交給那個人呢！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"하, 하지만… 그녀 또한 기사단을 대표하는 열두 기사 중 한 명이 아닌가?","JPN":"し、しかし……彼女もまた騎士団を代表する12騎士の一人ではないか？","ENG":"B-but... Wasn't she one of the Twelve Knights?","TWN":"但，但是…她也是代表騎士團的十二騎士之一，不是嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"양쪽 파벌에서 부단장을 맡아보기도 했으니, 어찌 보면 그 이상의 적임자도…….","JPN":"両方の派閥で副団長を務めた経歴もある。ある意味では彼女以上の適任者は……","ENG":"She served as Deputy Captain on both sides. In a way, no one's more qualified...","TWN":"曾在雙方派系中擔任副團長，從某種角度來看，沒有更合適的人選了……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그만-!","JPN":"そこまで！","ENG":"Enough!","TWN":"停下-！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"후우…… 좋다. 전통이 그러하니 원로원 또한 그 뜻에 따라야겠지.","JPN":"ふう……いいだろう。それが伝統なら、元老院もそれに従うべきだ。","ENG":"*Sigh...* Very well. If tradition demands it, the Council shall abide.","TWN":"呼……好吧。既然這是傳統，元老院也應該遵循這個意願吧。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"메데이아 경. 지금의 발언은 가문을 넘어 그대의 뜻이라 받아들여도 되겠나?","JPN":"メデイア卿。今の発言は家門とは別に、そなたの意志と捉えてよいだろうか？","ENG":"Dame Medea. May we take this as your personal stance, beyond your house?","TWN":"美狄亞。現在的發言可以理解為不僅代表家族，也代表你的意願嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"제 자신을 넘어, 전 세대 기사들을 대표하는 바입니다.","JPN":"私だけではなく、前の世代の騎士たちを代表して申し上げました。","ENG":"It is the will of not just myself, but all knights of the previous generation.","TWN":"不僅代表我，代表著全世代的騎士們。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"……그래. 그리 나온다면 어쩔 수 없지.","JPN":"……そうか。そこまで言うのなら仕方あるまい。","ENG":"...So be it. We have no choice.","TWN":"……是啊，如果是這樣的話，那就沒辦法了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"허나 의결은 미뤄졌을 뿐임을 명심하게.","JPN":"しかし、議決は延期されただけだということを忘れるな。","ENG":"But keep in mind, this only postpones the decision.","TWN":"但請記住，決議只是被推遲了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"언제까지고 자네 혼자 원로원의 뜻을 거스를 순 없어.","JPN":"いつまでもそなた一人で元老院に逆らうことはできん。","ENG":"You can't oppose the Council forever.","TWN":"你不能永遠一個人違背元老院的意願。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"예. 물론입니다.","JPN":"ええ、もちろんです。","ENG":"Yes. Of course.","TWN":"是的，當然。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"메데이아 경의 뜻을 받아들여, 현 안건에 대한 결정을 일시적으로 보류한다!","JPN":"メデイア卿の意見を受け入れ、本件の決定を一時的に保留する！","ENG":"The Council accepts Dame Medea's position. The matter is temporarily suspended!","TWN":"接受美狄亞的意願，暫時擱置當前議案的決定！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"원로원과 뜻을 달리 할 자, 앞으로 나와 그 이름을 밝혀라!","JPN":"元老院の意見に反対する者は前に出てその名を明かせ！","ENG":"If anyone here disagrees with the Council, step forward and declare your name!","TWN":"與元老院意見相左者，站出來報上名來！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"뒤늦게 나타나서 거들먹거리긴…….","JPN":"遅れて出てきたくせに偉そうに……","ENG":"Look who's swaggering in late...","TWN":"遲到還擺架子……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"너도 갈 데까지 갔구나, 메데이아? 하다하다 줄리아 녀석의 손을 빌리려 해?","JPN":"あんたも落ちるとこまで落ちたわね、メデイア？　ジュリアの手を借りようとするなんて。","ENG":"You've really hit rock bottom, Medea. Asking for help from that Julia girl now?","TWN":"你也走到這一步了嗎，美狄亞？居然想要借助茱莉亞那傢伙的手？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"음~.","JPN":"えーと。","ENG":"Hmm...","TWN":"嗯～"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"누구?","JPN":"誰？","ENG":"Who?","TWN":"誰？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"이, 이 가식덩어리가…!!","JPN":"こ、この猫かぶりが……！！","ENG":"Y-you two-faced faker...!","TWN":"你這個虛偽的傢伙…！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"모든 기사가 동의하였으니, 현 시간부로 사안에 대한 추가적인 발언은 금지한다.","JPN":"すべての騎士の同意の下、現時刻をもって本件に対する追加発言を禁止する。","ENG":"All knights have agreed. From this moment, no further discussion on the matter.","TWN":"所有騎士都已同意，從現在起禁止對該事項進行額外發言。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"오늘은 이만 해산하도록 하지.","JPN":"今日はここで解散としよう。","ENG":"This meeting is adjourned.","TWN":"今天就到此為止，解散吧。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"크으~. 한솔이 너도 원로 할아버지들이 쩔쩔매는 모습 봤지?","JPN":"くう～、イチロウ、元老のジジイたちがうろたえる姿、見た？","ENG":"Whoo! Hansol, you saw that, right? The Elders totally folded!","TWN":"哎喲～楊瀚，你也看到那些老傢伙手足無措的樣子了吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그런 누님이 있으면 진작 좀 부르지 그랬어!","JPN":"あんなお姉さんがいるなら、もっと早く呼んでくれればよかったのに！","ENG":"You should’ve told me you had a sister like that!","TWN":"有這樣的姊姊，早該叫我來啊！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그건 리브 경이 누님의 실체를 몰라서 그래요.","JPN":"リブ卿はあの人の正体を知らないからそんなことが言えるんです。","ENG":"Only because you don't know how scary she really is.","TWN":"那是因為莉芙不了解姊姊的真實面貌。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"성격으로 무구를 배정받는다면 양보다 사자나 황소에 적합한 사람이라고요.","JPN":"性格で武具が決まるなら、羊よりは獅子か牛が合っている人ですよ。","ENG":"If Armaments were handed out based on personality, she'd be better off with Leo or Taurus than Aries.","TWN":"如果根據性格來分配武器的話，那他更適合獅子或公牛，而不是羊。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어… 양도 성격은 까다로운 편 아니야?","JPN":"……羊だって気難しい性格なのは一緒じゃない？","ENG":"Uh... isn't Aries known for being temperamental too?","TWN":"呃……羊的性格也挺挑剔的，不是嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"양보다 더 사나운, 사자나 황소에 적합하다는 소리였어요.","JPN":"羊よりも狂暴な獅子と雄牛が合っているという意味です。","ENG":"Yeah, but she's even worse. Definitely more Leo or Taurus material.","TWN":"比羊更兇猛，適合獅子或公牛。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그래도 무사히 넘어가서 다행이에요~.","JPN":"でも、無事に終わってよかったです～。","ENG":"Still, I'm just glad things didn't go too badly.","TWN":"不過幸好大家都平安無事～"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아무렴. 우리 에리어스는 중간에 눈물까지 찔끔 흘렸잖아.","JPN":"そうだね。アリウスは途中涙まで見せたもんね。","ENG":"Totally. Arius even teared up in the middle of it all!","TWN":"當然啦。我們的埃里奧斯中途還流了幾滴眼淚呢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"저, 저 안 울었어요. 리브 언니!","JPN":"わ、私泣いてませんよ、リブさん！","ENG":"I-I did not cry, Liv!","TWN":"我，我沒有哭。莉芙姊姊！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"예이예이. 어련하시겠어?","JPN":"はいはい、わかりましたよ。","ENG":"Sure, sure. Whatever you say.","TWN":"來囉來囉。天啊，又開始胡言亂語了？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"단장이 돌아오면 고기나 먹으러 가자. 승전 기념 파티야!","JPN":"団長が帰ってきたら肉でも食べに行こう。祝勝会ってことで！","ENG":"Once Captain's back, we're going out for meat. Victory party!","TWN":"團長回來後我們去吃肉吧。慶祝勝利的派對！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그런데, 부단장. 아까부터 뭘 그렇게 뚫어져라 봐?","JPN":"ところで副団長、さっきから何をそんなに真剣に見てるの？","ENG":"By the way, Deputy, what've you been staring at?","TWN":"可是，副團長。你從剛才開始就一直盯著看什麼呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"줄리아 레온하르트에 관한 정보를 수집 중이었습니다.","JPN":"ジュリア・レオンハルトの情報を調べていました。","ENG":"I've been gathering intel on Julia Leonhardt.","TWN":"正在收集關於茱莉亞·里恩哈特的資訊。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그동안 샤레이드 건틀렛 챔피언으로서 도시의 왕처럼 행세하고 다닌 모양이군요.","JPN":"これまで、シャレードのガントレットチャンピオンとして街の王よろしく振る舞っていたようです。","ENG":"Seems she's been strutting around like royalty as the Gauntlet Champion.","TWN":"看來她一直以聖鎧冠軍的身份在城市裡像國王一樣行事。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에이, 뭐가 걱정이야? 듣자 하니 한솔이 누님이랑 친구라던데, 그럼 우리 편을 들겠지.","JPN":"え～、大丈夫じゃない？　聞いた感じ、イチロウのお姉さんと友だちみたいだし、きっと私たちの味方になってくれるよ。","ENG":"What's the big deal? Didn't Hansol say they're friends? She'll take our side.","TWN":"哎，擔心什麼呢？聽說你和楊瀚姊姊是朋友，那她肯定會站在我們這邊的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아뇨. 그 여자는 레드시프트로 전향한 변절자입니다.","JPN":"いいえ、あの人はレッドシフトに転向した変節者です。","ENG":"No. That woman is a traitor who defected to the Red Shift.","TWN":"不，那女人是叛變到紅移的叛徒。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 경은 상황을 보류시켰을 뿐. 상황이 마냥 낙관적인 건 아니예요.","JPN":"メデイア卿は事態を保留にさせてくれただけ。状況はあまり芳しくありません。","ENG":"All Dame Medea did was delay things. This is far from over.","TWN":"美狄亞只是暫時擱置了情況。情況並不完全樂觀。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"동의해요. 레드시프트 단원이 구태여 단장님을 도와줄 이유는 없으니까요.","JPN":"同意見です。レッドシフトの団員がわざわざ団長を助ける理由はありませんから。","ENG":"I agree. A Red Shift wouldn't help our Captain out of the kindness of her heart.","TWN":"同意。紅移小隊成員沒有必要特意去幫助團長。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"으으. 그럼, 단장님은……?","JPN":"ううっ。じゃあ団長は……？","ENG":"So then... what's going to happen to Captain...?","TWN":"呃呃。那麼，團長呢……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭘 그렇게 부정적으로 말해, 부단장? 에리어스가 또 울려고 하잖아!","JPN":"なにそんなに否定的になってるの、副団長？　アリウスがまた泣きそうになってるじゃん！","ENG":"Come on, Deputy. Don't be such a downer. You're gonna make Arius cry again!","TWN":"為什麼要這麼消極地說話，副團長？埃里奧斯又要哭了！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"저, 저 안 울… 훌쩍…!!","JPN":"な、泣いてません……ひっく……！","ENG":"I-I'm not... *Sniffle...!*","TWN":"我、我沒有哭……嗚咽……！！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"거듭 말하지만 듣고 싶은 것만 듣지 마세요. 그렇다고 방법이 없는 건 아닙니다.","JPN":"先程も言いましたが、聞きたいことだけ聞くのはあまり感心しません。それに、方法がないわけでもありません。","ENG":"I'll say it again. Don't hear only what you want to hear. But that doesn't mean we have no options.","TWN":"我再說一遍，不要只聽你想聽的。不過，也不是沒有辦法。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저흰 그녀가 챔피언인 건틀렛에 도전할 겁니다.","JPN":"私たちは彼女がチャンピオンをしているガントレットに挑みます。","ENG":"We'll challenge her in the Gauntlet.","TWN":"我們將挑戰她作為冠軍的聖鎧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"건틀렛이라면 TV에 나오는 그거? 거기 도전해서 어쩌려고?","JPN":"ガントレットって、テレビに出てるあれ？　それに挑んでどうするつもり？","ENG":"The thing on TV? What's that gonna do?","TWN":"聖鎧的話，是電視上出現的那個嗎？去挑戰那裡有什麼意義？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그곳에서 줄리아 레온하르트를 꺾은 뒤, 그녀의 별의 무구를 회수할 겁니다.","JPN":"そこでジュリア・レオンハルトを打ち破り、彼女の持つ星の武具を回収するんです。","ENG":"We'll defeat Julia Leonhardt and reclaim her Star Armament.","TWN":"在那裡擊敗茱莉亞·里恩哈特後，將回收她的星之武具。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 여자가 가장 명예롭게 여기는 건틀렛 리그.","JPN":"あの人が最も名誉としているガントレットリーグ。","ENG":"She holds the Gauntlet League in the highest regard.","TWN":"那個女人最引以為榮的聖鎧聯賽。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그곳에서 그녀를 꺾는다면 저희의 요구도 무시하기 어렵겠죠.","JPN":"そこで彼女を打ち負かせば、私たちの要求も無視できなくなるはずです。","ENG":"If we beat her there, she won't be able to ignore our demand.","TWN":"如果在那裡擊敗她的話，她就很難無視我們的要求了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어… 그렇게 하면 뭐가 달라져?","JPN":"えっ……そうしたら、何かが変わるの？","ENG":"Huh... And how does that change anything?","TWN":"呃……那樣做會有什麼不同呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"레온하르트 가문은 그녀의 존재로 골머리를 앓고 있는 상황입니다. 그런 상황에서 저희가 무구를 돌려준다면…….","JPN":"レオンハルト家も彼女のことで頭を悩ませている状況です。そんな中、私たちが武具を取り返したら……","ENG":"House Leonhardt sees her as a major headache. If we return her Armament under those circumstances...","TWN":"里恩哈特家族正因她的存在而頭疼。在這種情況下，如果我們把武器還給他們的話……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"가문이 저희에게 은혜를 입는 셈이군요!","JPN":"レオンハルトは私たちに借りができるわけですね！","ENG":"They'd owe us a favor!","TWN":"我們對家族施恩了啊！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"분명, 저희의 이야기를 들어줄 수밖에 없을 거예요!","JPN":"きっと、こちらの話を聞かざるを得なくなります！","ENG":"They'd have no choice but to listen to what we have to say!","TWN":"一定會聽我們的請求的！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예. 운이 좋아 다른 레드시프트 단원들의 정보까지 알아낸다면 그 이상 좋을 게 없겠죠.","JPN":"はい。運よく他のレッドシフト団員の情報まで掴めたなら、それ以上の成果はありません。","ENG":"Exactly. And if we're lucky, we might even get info on the other Red Shift members.","TWN":"是的。如果運氣好，能了解到其他紅移小組成員的資訊，那就再好不過了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"오오~. 뭐야, 부단장은 다 계획이 있었구나?","JPN":"おお～、なんだ～、副団長ったらちゃんと計画あるじゃん！","ENG":"Ooh! Deputy had this all planned out?","TWN":"喔喔～什麼呀，副團長原來是有計劃的啊？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그럼 정해졌네! 목표는 타도 줄리아 레온하르트, 건틀렛 우승이야!","JPN":"じゃあもう決まりだね！　目標はジュリア・レオンハルトを倒して、ガントレット優勝！","ENG":"Well, that settles it! Our objective is to defeat Julia Leonhardt and win the Gauntlet!","TWN":"那麼就決定了！目標是打倒茱莉亞·里恩哈特，贏得聖鎧冠軍！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"타도~. 우승~!","JPN":"倒す～！　優勝～！","ENG":"Defeat! Win!","TWN":"打倒～勝利～！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예. 그러니 우선 단장님이 돌아 오시길 기다리죠.","JPN":"はい。ですからまずは団長が戻られるのを待ちましょう。","ENG":"Yes. But first, we wait for the Captain's return.","TWN":"是的。那麼我們先等團長回來吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단의 힘을 합친다면… 걱정할 건 아무것도 없을 거예요.","JPN":"騎士団の力を合わせれば……心配することは何もありません。","ENG":"As long as we stand united... there's nothing to fear.","TWN":"如果我們團結騎士團的力量……就沒有什麼可擔心的了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"처음부터 무리였다.","JPN":"最初から無理だったんだ。","ENG":"It was doomed from the start.","TWN":"從一開始就不可能。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>그 사람</color>을 흉내내면 이상적인 기사가 될 수 있을 것이라고.","JPN":"<color=#ffd34c>あの人</color>の真似をすれば理想の騎士になれると。","ENG":"I thought if I just copied <color=#ffd34c>that person</color>, I could become the ideal knight.","TWN":"<color=#ffd34c>模仿那個人</color>的話，就能成為理想的騎士。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"스스로에게 암시를 걸어 착각에 빠졌었다.","JPN":"自分に暗示をかけて、勘違いしていた。","ENG":"I hypnotized myself and sank into a delusion.","TWN":"給自己施加了暗示，陷入了錯覺。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"하나뿐인 가족조차 지키지 못한 내게, 타인을 지킬 힘 따윈 없었는데.","JPN":"たった一人の家族すら守れなかった私に、他人を守る力があるはずがなかった。","ENG":"When I couldn't even protect my only family, how could I protect anyone else?","TWN":"連唯一的家人都無法保護的我，又怎會有保護他人的力量呢。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어디가요, 에스텔?","JPN":"どこへ行くのですか？　エステル。","ENG":"Where are you off to, Esther?","TWN":"你要去哪兒，艾斯特洛索？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이쪽은 귀찮은 원로 자리까지 도맡아버렸는데, 설마 고맙단 말도 없이 사라지려는 거?","JPN":"面倒な元老の席まで引き受けてあげたっていうのに、お礼も言わずに消えるつもり？","ENG":"I just took on this annoying Elder seat for your sake, and you're leaving without a word?","TWN":"我這邊連麻煩的元老職位都包攬了，難道你想不說聲謝謝就消失嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"딱히, 도와달라 말한 적 없어요.","JPN":"別に、助けてくれと頼んだ覚えはありません。","ENG":"I never asked for your help.","TWN":"不，我沒說過要幫忙。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"차가워라~. 하긴, 예전부터 에스텔은 저보다 줄리아를 훨씬 따랐었죠.","JPN":"冷たいわね～。まあ、昔からエステルは私よりジュリアを慕っていましたもの。","ENG":"So cold. Though I guess you always liked Julia better than me.","TWN":"真冷淡啊～不過，從以前開始艾斯特就比起我更親近茱莉亞呢。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"처음부터 떠날 생각이었군요, 당신?","JPN":"最初から去るつもりだったんですね、あなた。","ENG":"You were planning to leave from the start, weren't you?","TWN":"你一開始就打算離開嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아아~. 이럴 줄 알았으면 오지 말 걸. 괜히 돌아와서 시간낭비만 했네.","JPN":"ああ～。こんなことになるなら来なければよかった。時間を無駄遣いしてしまったわ。","ENG":"*Sigh* Shouldn't have bothered coming back. What a waste of time.","TWN":"啊啊～早知道這樣就不來了。白白回來浪費時間了。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제 알바 아닙니다.","JPN":"私とは関係ありません。","ENG":"Not my problem.","TWN":"那不關我的事。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"메데이아 경이라면 어차피, 다른 목적이 있어 본부에 온 게 아닙니까.","JPN":"メデイア卿であれば、どうせ別の目的があって本部に来たのでしょう。","ENG":"You had your own reasons for coming to HQ, didn't you?","TWN":"美狄亞，反正你來總部是另有目的吧。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"와, 이제 연기할 생각도 없네? 오빠 흉내는 그만두기로 한 거예요?","JPN":"わあ、もう演じる気もないの？　お兄さんの真似はもうやめたのかしら。","ENG":"Wow, not even pretending anymore? Dropping the big brother act?","TWN":"哇，現在連演戲的打算都沒有了嗎？決定不再模仿哥哥了嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"피차일반 아닙니까. 가면을 쓰고 광대 노릇을 하는 건.","JPN":"お互い様ではありませんか。仮面をかぶって道化を演じているのは。","ENG":"We're no different. Hiding behind masks, playing the clown.","TWN":"彼此彼此，不都是戴著面具的小丑嗎。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"당신이 떠나면 지금의 기사단은 흔들릴 거예요.","JPN":"あなたが去れば、今の騎士団は揺らぐことになります。","ENG":"If you leave, the Order's going to fall apart.","TWN":"如果你離開，現在的騎士團會動盪的。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"후회하지 않을 자신 있어요?","JPN":"後悔しない自信はありますか？","ENG":"You sure you won't regret it?","TWN":"有信心不會後悔嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……저는 지금의 제 자신을 용서할 수 없습니다.","JPN":"……私は今の自分を許すことができません。","ENG":"...I can't forgive who I am right now.","TWN":"……我無法原諒現在的自己。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아무 각오도 하지 못한 채 동료들의 발목을 잡고.","JPN":"何の覚悟もないまま、仲間の足を引っ張り……","ENG":"I held back everyone around me without even preparing myself.","TWN":"毫無準備地拖累了同伴。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"불건한 망념에 사로잡힌 나머지 기사단의 정의에 의문을 품었어요.","JPN":"妄執に囚われて、騎士団の正義を疑ってしまいました。","ENG":"I got lost in impure thoughts, and began to question the Order's definition of justice.","TWN":"被不健康的妄念所困，開始質疑騎士團的正義。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"언젠가 제 부덕함이 누군가를 잘못된 길로 이끌지도 모른다는 것이 두렵습니다.","JPN":"いつか私の不徳が誰かを誤った道へ導いてしまうのではないか、それが怖いのです。","ENG":"I'm scared that one day, my failings might lead someone else down the wrong path.","TWN":"我害怕有一天我的妄念會引導某人走上錯誤的道路。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"별의 가호… 버고 소드가 제 부름에 응하지 않는 것 또한 그런 이유겠죠.","JPN":"星の加護……ヴァルゴソードが私の呼びかけに応えないのも、それが理由なのでしょう。","ENG":"The Blessing of the Stars... The Virgo Sword won't answer my call anymore... that must be why.","TWN":"星星的守護……大概連布林加夫之劍都不回應我的召喚也是這個原因吧。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그러니 모든 책임을 짊어지고 떠나겠습니다.","JPN":"だから私はすべての責任を背負って、去るつもりです。","ENG":"So I'll take full responsibility, and leave.","TWN":"所以我將承擔所有責任離開。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그게 동료들에게 보탬이 되는 유일한 방법이니까요.","JPN":"それが仲間たちの役に立つ、唯一の道ですから。","ENG":"That's the only way I can still be of use to my comrades.","TWN":"因為那是唯一能幫助同伴的方法。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That is…","TWN":"那是……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"됐다. 네 맘대로 하세요. 파벌이 나뉘건 단장이 바뀌건 솔직히 제 알 바는 아니니까요.","JPN":"もういいわ。好きにしたら？　派閥が分かれようが団長が変わろうが、正直私には関係ないもの。","ENG":"Fine. Do whatever you want. Whether the factions split or the captain changes, I honestly don't care anymore.","TWN":"好了，隨你便吧。派系分裂也好，團長更換也罷，說實話我不關心。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그동안 한솔이를 맡아준 것도 있으니 원로 자리를 맡는 건 쌤쌤으로 칠게요.","JPN":"今までイチロウの面倒を見てもらったから、元老を務めることについてはチャラにしてあげますわ。","ENG":"You took care of Hansol for me, so I'll call it even by taking the Elder's seat.","TWN":"這段時間你照顧了楊瀚，所以我就把長老的位置算作扯平了。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"떠나기 전, 한 가지 질문이 있습니다, 메데이아 경.","JPN":"去る前に、一つだけ聞きたいことがあります、メデイア卿。","ENG":"Before I go, I have one question, Dame Medea.","TWN":"離開之前，我有一個問題，美狄亞。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"뭔데요? 귀찮은 질문이라면 사양인데.","JPN":"何ですか？　面倒な質問なら遠慮してほしいけど。","ENG":"What is it? If it's a hassle, I'd rather not hear it.","TWN":"什麼事？如果是麻煩的問題就免了。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오빠가 단장의 책임을 등한시하고 도망쳤다는 말을 저는 이제껏 믿지 않았습니다.","JPN":"兄が団長の責任を疎かにして逃げたという話を、私は今まで信じませんでした。","ENG":"I have never believed the claim that my brother abandoned his duties as captain and ran away.","TWN":"我一直不相信哥哥會逃避團長的責任。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만 만약… 오빠도 저와 비슷한 문제를 겪었다면.","JPN":"ですが、もし……兄も私と同じような問題を抱えていたのだとしたら。","ENG":"But... if he went through something similar to what I'm feeling now...","TWN":"但是如果……哥哥也遇到了和我類似的問題。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그랬다면, 현실에서 도망쳤을까요?","JPN":"そうしたら、兄は現実から逃げたと思いますか？","ENG":"If that's the case... Do you think he would have fled from reality?","TWN":"如果是這樣的話，會在現實中逃跑嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아뇨.","JPN":"いいえ。","ENG":"No.","TWN":"不。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그 녀석은 에스텔과는 달리, 현실에 좌절할지언정 책임을 저버리는 사람은 아니에요.","JPN":"あの人はエステルとは違って、現実に打ちのめされても責任を放棄するような人じゃありません。","ENG":"Unlike you, Esther, he wasn't the kind of man to abandon his responsibilities, even if the world crushed him.","TWN":"那傢伙和艾斯特不同，即使對現實感到失望，也不會逃避責任。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"오히려 자신의 목숨을 불태워 타인의 빛이 되어주는 존재죠.","JPN":"むしろ、自らの命を燃やして他人の光となる人です。","ENG":"He was the type who'd burn himself up, just to be someone else's light.","TWN":"反而成為燃燒自己的生命，成為他人光芒的存在。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"질문의 답이 되었을까요?","JPN":"これで質問の答えになったかしら？","ENG":"Does that answer your question?","TWN":"不知道我的回答有沒有解決你的疑問？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……예.","JPN":"……はい。","ENG":"...Yes.","TWN":"……是的。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"감사합니다, 메데이아 경.","JPN":"ありがとうございます、メデイア卿。","ENG":"Thank you, Dame Medea.","TWN":"謝謝你，美狄亞。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하아. 누가 남매 아니랄까 봐, 고민하는 표정도 똑같네.","JPN":"はあ……さすがは兄妹、悩んでる顔までそっくりなのね。","ENG":"*Sigh* You really are siblings. You even wear the same expression when you're agonizing over something.","TWN":"哈。真不愧是兄妹，連煩惱的表情都一模一樣。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"오빠나 동생이나 뭘 그리 어렵게 생각하는지.","JPN":"兄も妹も、どうしてそんなに頭が固いのかしら。","ENG":"Why do you both have to make everything so hard on yourselves?","TWN":"哥哥還是妹妹，為什麼要想得那麼複雜呢。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"그러니 만약, 에스텔이 선택해야 하는 순간이 온다면.","JPN":"だからもし、エステルが選ばなければならない時が来たら。","ENG":"If the day ever comes when Esther has to choose...","TWN":"所以，如果有一天，艾斯特必須做出選擇。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"제 동생이 기사의 <color=#ffd34c>운명</color>에서 벗어날 수 있도록 도와주세요.","JPN":"妹が騎士の<color=#ffd34c>運命</color>から逃れられるように手伝ってあげてください。","ENG":"Please help my sister break free from the knight's <color=#ffd34c>fate</color>.","TWN":"請幫助我的妹妹擺脫騎士的<color=#ffd34c>命運</color>。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"그게 분명… 그 아이의 행복을 위한 일이니까.","JPN":"それがきっと……あの子の幸せのためだから。","ENG":"That's... the only path to her happiness.","TWN":"那一定是……為了孩子的幸福。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"대체 무슨 생각으로 그런 말을 한 건지는 아직도 모르겠지만…….","JPN":"いったいどういうつもりでそんなことを言ったのかはわからないけど……","ENG":"I still don't get what he was thinking when he said that...","TWN":"雖然我至今仍不明白你到底是出於什麼想法才說出那樣的話……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L41_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"약속은 지켰어, <color=#ffd34c>단장</color>.","JPN":"これで約束は守ったわ、<color=#ffd34c>団長</color>。","ENG":"But I kept my promise, <color=#ffd34c>Captain</color>.","TWN":"我遵守了約定，<color=#ffd34c>團長</color>。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이제 남은 건, 네 동생의 몫이야.","JPN":"あとは、あなたの妹次第よ。","ENG":"The rest is up to your sister.","TWN":"現在剩下的，就是你妹妹的份了。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};